\[ O(N) \] <pre><code>#include &lt;bits/stdc++.h&gt;
#define int long long

using namespace std;

string s;
int pos = 0;

int Multi();
int Plus();
int g();

int Multi() {
    int res = Plus();
    while (pos &lt; s.size() &amp;&amp; s[pos] == '*') {
        pos++;
        res *= Plus();
    }
    return res;
}

int Plus() {
    int res = g();
    while (pos &lt; s.size() &amp;&amp; s[pos] == '+') {
        pos++;
        res += g();
    }
    return res;
}

int g() {
    if (s[pos] == 'f') {
        pos++;
        pos++;

        vector&lt;int&gt; a;
        a.emplace_back(Multi());

        while (pos &lt; s.size() &amp;&amp; s[pos] == ',') {
            pos++;
            a.emplace_back(Multi());
        }

        pos++;

        int mx = *max_element(a.begin(), a.end());
        int mn = *min_element(a.begin(), a.end());

        return mx - mn;
    } else {
        int n = 0;
        while (pos &lt; s.size() &amp;&amp; isdigit(s[pos])) {
            n = n * 10 + (s[pos] - '0');
            pos++;
        }

        return n;
    }
}

signed main() {
    cin &gt;&gt; s;

    cout &lt;&lt; Multi();

    return 0;
}
